  private me() { return this.flow && this.state ? this.state.players[this.flow.game.playerId] : undefined; }
  private previewSpell(elements: Element[]) { const me = this.me(); return me ? resolveScrollSpell(elements, me, Date.now()) ?? resolveSpell(elements) : resolveSpell(elements); }
  private nearbyLoot() { return this.state ? Object.values(this.state.loot).filter((entry) => distance(this.local, entry.position) <= 125) : []; }
  private nearbyMerchant() { const merchant = this.state?.merchant; return merchant && distance(this.local, merchant.position) <= merchant.radius + 90 ? merchant : null; }
