    if (action.kind === 'toggle-spellbook') { this.inventoryOpen = false; this.spellbookOpen = !this.spellbookOpen; this.selectedItem = null; this.fusionIds = []; return true; }
    if (action.kind === 'close-spellbook') { this.spellbookOpen = false; return true; }
    if (action.kind === 'encyclopedia-spells') { this.encyclopediaTab = 'spells'; return true; }
    if (action.kind === 'encyclopedia-controls') { this.encyclopediaTab = 'controls'; return true; }
    if (action.kind === 'select-item' && action.source && action.itemId) { this.selectedItem = { source: action.source, itemId: action.itemId, entityId: action.entityId }; return true; }
